18	const DirName = ".ddx"
19	
20	type WorktreeRegistry = worktreeRegistry
21	type WorktreeRegistryEntry = worktreeRegistryEntry
22	
23	func InTree(projectRoot string, elems ...string) string {
24		parts := append([]string{projectRoot, DirName}, elems...)
25		return filepath.Join(parts...)
26	}
27	
28	func JoinHome(home string, elems ...string) string {
29		parts := append([]string{home, DirName}, elems...)
30		return filepath.Join(parts...)
31	}
