52	func ExistingJoinProject(ctx context.Context, projectRoot string, elems ...string) (string, bool) {
53		root, ok := ExistingPath(ctx, projectRoot)
54		if !ok {
55			return "", false
56		}
57		parts := append([]string{root}, elems...)
58		return filepath.Join(parts...), true
59	}
