61	func JoinProject(projectRoot string, elems ...string) string {
62		return JoinProjectContext(context.Background(), projectRoot, elems...)
63	}
64	
65	func JoinProjectContext(ctx context.Context, projectRoot string, elems ...string) string {
66		parts := append([]string{Path(ctx, projectRoot)}, elems...)
67		return filepath.Join(parts...)
68	}
