105	func LoadWorktreeRegistry(ctx context.Context, projectRoot string) (WorktreeRegistry, error) {
106		root := Path(ctx, projectRoot)
107		return readWorktreeRegistry(filepath.Join(root, "worktrees.json"))
108	}
